            columnIdlePeriodMaxCountOfChecks.AllowDBNull = false;
            table.Columns.Add(columnIdlePeriodMaxCountOfChecks);

            var columnIdlePeriodCheckCounter = new DataColumn("IdlePeriodCheckCounter", typeof(int));
            columnIdlePeriodCheckCounter.AllowDBNull = false;
            table.Columns.Add(columnIdlePeriodCheckCounter);

            var columnIdlePeriodMaxSeconds = new DataColumn("IdlePeriodMaxSeconds", typeof(int));
            columnIdlePeriodMaxSeconds.AllowDBNull = false;
            table.Columns.Add(columnIdlePeriodMaxSeconds);

            return table;
        }

        public static void SaveEntity2DataTable(DataTable table, BvSurveyListAlertsViewConfigurationEntity entity)
        {
            var rowData = new object[]
                {
                    entity.UpdatingTime,
                    entity.LastCall,
                    entity.SyncUpdatingTime,
                    entity.SyncLastCall,
                    entity.IdlePeriodMaxCountOfChecks,
                    entity.IdlePeriodCheckCounter,
                    entity.IdlePeriodMaxSeconds
                };

            table.Rows.Add(rowData);
        }
    }
